#include <stdio.h>
#include <stdlib.h>

long long maxSubarraySum(long long *arr, int n) {
    long long cur = arr[0];
    long long best = arr[0];
    for (int i = 1; i < n; ++i) {
        if (cur + arr[i] > arr[i])
            cur = cur + arr[i];
        else
            cur = arr[i];
        if (cur > best) best = cur;
    }
    return best;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        printf("%lld\n", maxSubarraySum(a, N));
        free(a);
    }
    return 0;
}

